INSERT INTO news (title, slug, description, content, category, status, user_id, published_at) VALUES
('FMLider expande operações para a SADC', 'fmlider-expande-operacoes-sadc', 'Nova rota semanal de camião para Lusaca, Zâbia, com tempos de trânsito de 5 dias.', 'A FMLider anunciou a abertura de nova rota rodoviária Luanda-Lusaca com saída semanal. O serviço inclui desalfandegamento integrado e seguro all risks.', 'Expansão', 'published', 1, NOW()),
